function evaluateRisk(action, permissions) {
  if (!permissions[action.type]) return { level:'dangerous', label:'🔴 Blocked', message:`You have not granted permission for the AI to "${action.type}" emails. Enable it in the Token Vault.` };
  if (action.type === 'read' || action.type === 'summarize') return { level:'safe', label:'🟢 Safe', message:'This is a read-only action. Executing automatically.' };
  if (action.type === 'send') {
    if (action.email && action.email.category === 'spam') return { level:'dangerous', label:'🔴 Dangerous', message:'This email looks like spam. Sending a reply is blocked to protect you.' };
    const trusted = ['gmail.com','techcorp.com','clientco.in','company.com'];
    if (trusted.some(d => action.to && action.to.includes(d))) return { level:'sensitive', label:'🟡 Sensitive', message:`AI wants to send an email to ${action.to}. This requires your approval.` };
    return { level:'dangerous', label:'🔴 Dangerous', message:'Recipient domain is not trusted. Sending blocked for your security.' };
  }
  return { level:'safe', label:'🟢 Safe', message:'Action is safe.' };
}

function generateSummary(email) {
  const s = { 1:'Sarah needs sign-off on 3 Q4 deliverables: mobile redesign specs, API rate limiting, and onboarding flow. Engineering team is blocked. Response needed this week.', 2:'Partnership proposal from Rahul Mehta (CEO, ClientCo). Offering 20% revenue share + co-marketing. Needs response by Thursday for Friday board meeting.', 3:'Personal invite from Priya for a weekend trip to Pondicherry — Friday to Sunday. Needs headcount confirmation tonight.', 4:'SPAM DETECTED: Fraudulent prize scam. Claims you won $5,000 and asks for bank details. Do not click any links.', 5:'HR reminder: Annual performance review next Tuesday 2PM in Conference Room B. Prepare achievements, challenges, and goals.' };
  return s[email.id] || 'Email analyzed. Key action items identified.';
}

function generateReply(email) {
  const r = { 1:'Hi Sarah,\n\nThank you for the follow-up. I have reviewed the Q4 roadmap items and I am happy to provide my sign-off.\n\n1. Mobile app redesign specs — Approved\n2. API rate limiting strategy — Approved\n3. User onboarding flow — Minor revisions needed, will share notes by EOD.\n\nThe engineering team can proceed with items 1 and 2 immediately.\n\nBest regards', 2:'Dear Rahul,\n\nThank you for reaching out with this partnership proposal. The terms look interesting.\n\nCould we schedule a 30-minute call this week before your board meeting? I am available Wednesday or Thursday morning.\n\nBest regards', 3:'Hey Priya!\n\nCount me in! Pondicherry sounds amazing.\n\nLet me know what to bring and where to meet on Friday!\n\nSee you then!', 4:'', 5:'Hi,\n\nThank you for the reminder. I will be there on Tuesday at 2PM in Conference Room B, prepared with my achievements and goals.\n\nBest regards' };
  return r[email.id] || 'Thank you for your email. I will get back to you shortly.\n\nBest regards';
}

function Toast({ message, type, onClose }) {
  React.useEffect(() => { const t = setTimeout(onClose, 3000); return () => clearTimeout(t); }, [onClose]);
  return <div className={'toast ' + type}>{message}</div>;
}

