function Dashboard() {
  const { user, logout } = useAuth0();
  const [emails, setEmails] = useState(MOCK_EMAILS);
  const [selected, setSelected] = useState(MOCK_EMAILS[0]);
  const [composeMode, setComposeMode] = useState('reply');
  const [permissions, setPermissions] = useState({ read:true, summarize:true, send:false });
  const [log, setLog] = useState([]);
  const [pendingRisk, setPendingRisk] = useState(null);
  const [aiResult, setAiResult] = useState(null);
  const [composeTo, setComposeTo] = useState('');
  const [composeSubject, setComposeSubject] = useState('');
  const [composeBody, setComposeBody] = useState('');
  const [sending, setSending] = useState(false);
  const [toast, setToast] = useState(null);
  const [loadingAction, setLoadingAction] = useState(null);
  const [showProfile, setShowProfile] = useState(false);
  const [profileName, setProfileName] = useState(user?.name || '');
  const [profileEmail, setProfileEmail] = useState(user?.email || '');
  const mainPanelRef = useRef();

  const role = user && user['https://guardy-ai/role'] ? user['https://guardy-ai/role'] : 'user'; // Simulate role from Auth0
  const trustScore = Math.min(100, (user?.logins_count || 1) * 10); // Mock trust score based on logins

  const addLog = (msg) => setLog(l => [{ msg, time: new Date().toLocaleTimeString() }, ...l.slice(0,19)]);
  const showToast = (message, type='success') => setToast({ message, type });

  const scrollToBottom = () => {
    if (mainPanelRef.current) {
      mainPanelRef.current.scrollTo({ top: mainPanelRef.current.scrollHeight, behavior: 'smooth' });
    }
  };

  useEffect(() => {
    if (mainPanelRef.current) {
      mainPanelRef.current.scrollTop = mainPanelRef.current.scrollHeight;
    }
  }, []);

  const openNewEmail = () => {
    setSelected(null);
    setComposeMode('new');
    setComposeTo('');
    setComposeSubject('');
    setComposeBody('');
    setAiResult(null);
  };

  const handleAction = (type, email) => {
    const risk = evaluateRisk({ type, email, to: email.from }, permissions);
    if (risk.level === 'safe') { executeAction(type, email); }
    else { setPendingRisk({ ...risk, action: { type, email } }); }
  };

  const executeAction = (type, email) => {
    setLoadingAction(type+'-'+email.id);
    setTimeout(() => {
      setLoadingAction(null);
      if (type === 'read') {
        setSelected(email);
        setComposeMode('reply');
        setEmails(prev => prev.map(e => e.id === email.id ? { ...e, unread:false } : e));
        setAiResult(null);
        setComposeTo(''); setComposeSubject(''); setComposeBody('');
        addLog('🟢 Read email from ' + email.name);
      } else if (type === 'summarize') {
        setSelected(email);
        setComposeMode('reply');
        setAiResult({ type:'summary', text: generateSummary(email) });
        addLog('🟢 Summarized email from ' + email.name);
        showToast('✨ AI summary generated!');
      } else if (type === 'reply') {
        setSelected(email);
        setComposeMode('reply');
        setComposeTo(email.from);
        setComposeSubject('Re: ' + email.subject);
        setComposeBody(generateReply(email));
        setAiResult(null);
        addLog('🟢 AI reply drafted for ' + email.name);
        showToast('✨ AI reply drafted!');
      }
    }, 800);
  };

  const handleSend = async () => {
    if (!composeTo || !composeBody) { showToast('Please fill in recipient and message', 'error'); return; }
    const risk = evaluateRisk({ type:'send', email: composeMode === 'new' ? { category:'personal' } : selected, to:composeTo }, permissions);
    if (risk.level === 'dangerous') { setPendingRisk({ ...risk, action:{ type:'send', email:selected } }); return; }
    if (risk.level === 'sensitive') { setPendingRisk({ ...risk, action:{ type:'send', email:selected, isFinalSend:true } }); return; }
    await doSend();
  };

  const doSend = async () => {
    setSending(true);
    try {
      const serviceId = process.env.REACT_APP_EMAILJS_SERVICE_ID;
      const templateId = process.env.REACT_APP_EMAILJS_TEMPLATE_ID;
      const publicKey = process.env.REACT_APP_EMAILJS_PUBLIC_KEY;
      if (serviceId && templateId && publicKey) {
        await emailjs.send(serviceId, templateId, {
          to_email: composeTo,
          subject: composeSubject,
          message: composeBody,
          from_name: user && user.name ? user.name : 'Guardy AI',
        }, publicKey);
        addLog('📤 Real email sent to ' + composeTo + ' via EmailJS!');
        showToast('📤 Email sent to ' + composeTo + '!');
      } else {
        await new Promise(r => setTimeout(r, 1000));
        addLog('📤 [Simulated] Email sent to ' + composeTo);
        showToast('📤 Email sent to ' + composeTo + '!');
      }
      setComposeTo(''); setComposeSubject(''); setComposeBody('');
    } catch(err) {
      showToast('Send failed. Check EmailJS config.', 'error');
      addLog('❌ Send failed: ' + (err.text || err.message || 'Unknown error'));
    }
    setSending(false);
  };

  const togglePerm = (key) => {
    setPermissions(p => {
      const v = !p[key];
      addLog((v ? '🔓 Granted' : '🔒 Revoked') + ' AI permission: ' + key);
      return { ...p, [key]:v };
    });
  };

  return (
    <><style>{styles}</style>
    <div className="bg-canvas"><div className="orb orb-1"/><div className="orb orb-2"/></div>
    <div className="bg-grid"/>
    <div className="dash-wrap">
      <nav className="dash-nav">
        <div className="dash-logo">🛡️ Guardy AI</div>
        <div className="dash-user">
          {user && user.picture && <img src={user.picture} alt="avatar" className="user-avatar"/>}
          <span className="user-name">{user && (user.name || user.email)}</span>
          <button className="btn-logout" onClick={()=>setShowProfile(true)}>Profile</button>
          <button className="btn-logout" onClick={()=>logout({logoutParams:{returnTo:window.location.origin}})}>Log out</button>
        </div>
      </nav>

      <div className="dash-body">
        {/* Sidebar */}
        <div className="sidebar">
          <div className="sidebar-title">🔐 Token Vault</div>
          <p style={{fontSize:12,color:'var(--muted)',marginBottom:16,lineHeight:1.5}}>Control what Guardy AI can do on your behalf.</p>
          {[{key:'read',label:'👁 Read emails'},{key:'summarize',label:'📝 Summarize'},{key:'send',label:'📤 Send emails'}].map(({key,label})=>(
            <div className="perm-item" key={key}>
              <span className="perm-label">{label}</span>
              <label className="toggle">
                <input type="checkbox" checked={permissions[key]} onChange={()=>togglePerm(key)}/>
                <span className="toggle-slider"/>
              </label>
            </div>
          ))}
          <div className="vault-badge"><span>🔒</span> Auth0 secured session</div>
          <div className="vault-badge" style={{marginTop:16}}><span>🤖</span> AI Trust Score: {trustScore}/100</div>
          <div className="log-section">
            <div className="log-title">📋 Action Log</div>
            {log.length === 0 && <div style={{fontSize:12,color:'var(--muted)'}}>No actions yet.</div>}
            {log.map((entry,i)=>(
              <div className="log-item" key={i}>
                <span style={{color:'var(--muted)',marginRight:6}}>{entry.time}</span>{entry.msg}
              </div>
            ))}
          </div>
        </div>

        {/* Inbox */}
        <div className="main-panel" ref={mainPanelRef}>
          <div className="panel-header">
            <div className="panel-title">📬 Inbox</div>
            <div style={{display:'flex',alignItems:'center',gap:12}}>
              <span style={{fontSize:13,color:'var(--muted)'}}>{emails.filter(e=>e.unread).length} unread</span>
              <button onClick={scrollToBottom} style={{fontSize:13, color:'var(--muted)', background:'none', border:'none', cursor:'pointer'}}>⬇️ Scroll to Bottom</button>
              <button className="new-email-btn" onClick={openNewEmail}>✏️ New Email</button>
            </div>
          </div>
          {emails.map(email=>(
            <div key={email.id}
              className={'email-card'+(email.unread?' unread':'')+(selected&&selected.id===email.id&&composeMode==='reply'?' selected':'')}
              onClick={()=>{setSelected(email);setComposeMode('reply');setAiResult(null);setComposeTo('');setComposeSubject('');setComposeBody('');}}>
              <div className="email-meta">
                <div className="email-from" style={{color:email.unread?'var(--text)':'var(--muted)'}}>
                  {email.name}
                  {email.category==='spam'&&<span style={{marginLeft:8,fontSize:11,background:'rgba(255,77,77,0.15)',color:'var(--danger)',padding:'2px 8px',borderRadius:4}}>SPAM</span>}
                  {email.category==='work'&&<span style={{marginLeft:8,fontSize:11,background:'rgba(108,99,255,0.15)',color:'var(--accent)',padding:'2px 8px',borderRadius:4}}>WORK</span>}
                  {email.category==='business'&&<span style={{marginLeft:8,fontSize:11,background:'rgba(0,212,255,0.15)',color:'var(--accent2)',padding:'2px 8px',borderRadius:4}}>BIZ</span>}
                </div>
                <div className="email-time">{email.time}</div>
              </div>
              <div className="email-subject">{email.subject}</div>
              <div className="email-preview">{email.preview}</div>
              <div className="email-actions" onClick={e=>e.stopPropagation()}>
                <button className={'action-btn'+(loadingAction==='read-'+email.id?' loading':'')} onClick={()=>handleAction('read',email)}>{loadingAction==='read-'+email.id?'⏳':'👁'} Read</button>
                <button className={'action-btn'+(loadingAction==='summarize-'+email.id?' loading':'')} onClick={()=>handleAction('summarize',email)}>{loadingAction==='summarize-'+email.id?'⏳':'🤖'} Summarize</button>
                {email.category!=='spam'&&<button className={'action-btn'+(loadingAction==='reply-'+email.id?' loading':'')} onClick={()=>handleAction('reply',email)}>{loadingAction==='reply-'+email.id?'⏳':'✍️'} AI Reply</button>}
              </div>
            </div>
          ))}
        </div>

        {/* Right Panel */}
        <div className="detail-panel">
          {composeMode === 'new' && (
            <div className="compose-section" style={{marginTop:0}}>
              <div className="compose-header">✏️ New Email</div>
              <label className="compose-label">TO</label>
              <input className="compose-input" value={composeTo} onChange={e=>setComposeTo(e.target.value)} placeholder="recipient@example.com"/>
              <label className="compose-label">SUBJECT</label>
              <input className="compose-input" value={composeSubject} onChange={e=>setComposeSubject(e.target.value)} placeholder="Subject"/>
              <label className="compose-label">MESSAGE</label>
              <textarea className="compose-textarea" value={composeBody} onChange={e=>setComposeBody(e.target.value)} placeholder="Write your message here..."/>
              <button className="send-btn" onClick={handleSend} disabled={sending}>{sending?'⏳ Sending...':'📤 Send Email'}</button>
              <button onClick={()=>{setComposeMode('reply');setSelected(MOCK_EMAILS[0]);}} style={{width:'100%',marginTop:8,padding:'10px',background:'transparent',border:'1px solid var(--border)',borderRadius:10,color:'var(--muted)',fontFamily:'DM Sans,sans-serif',fontSize:13,cursor:'pointer'}}>← Back to Inbox</button>
            </div>
          )}

          {composeMode === 'reply' && selected && (
            <>
              <div className="detail-title">{selected.subject}</div>
              <div className="detail-from">From: {selected.from}</div>
              <div className="detail-body" style={{whiteSpace:'pre-line'}}>{selected.body}</div>
              {aiResult && aiResult.type==='summary' && (
                <div className="ai-result">
                  <div className="ai-result-label">🤖 AI Summary</div>
                  <div className="ai-result-text">{aiResult.text}</div>
                </div>
              )}
              {selected.category!=='spam' && (
                <div className="compose-section">
                  <div className="compose-header">↩️ Reply</div>
                  <label className="compose-label">TO</label>
                  <input className="compose-input" value={composeTo} onChange={e=>setComposeTo(e.target.value)} placeholder="recipient@example.com"/>
                  <label className="compose-label">SUBJECT</label>
                  <input className="compose-input" value={composeSubject} onChange={e=>setComposeSubject(e.target.value)} placeholder="Subject"/>
                  <label className="compose-label">MESSAGE</label>
                  <textarea className="compose-textarea" value={composeBody} onChange={e=>setComposeBody(e.target.value)} placeholder="Write your reply..."/>
                  <button className="send-btn" onClick={handleSend} disabled={sending}>{sending?'⏳ Sending...':'📤 Send Reply'}</button>
                </div>
              )}
            </>
          )}

          {composeMode === 'reply' && !selected && (
            <div style={{color:'var(--muted)',fontSize:14,textAlign:'center',marginTop:40}}>
              <div style={{fontSize:32,marginBottom:12}}>📬</div>
              Select an email to read it<br/>or click <strong style={{color:'var(--accent)'}}>✏️ New Email</strong> to compose
            </div>
          )}
        </div>
      </div>
    </div>

    <RiskModal
      risk={pendingRisk}
      onConfirm={async()=>{
        const action = pendingRisk.action;
        setPendingRisk(null);
        if (action.isFinalSend) { await doSend(); }
        else { executeAction(action.type, action.email); }
      }}
      onCancel={()=>{
        addLog('❌ Blocked: ' + pendingRisk.action.type + ' — ' + pendingRisk.label);
        setPendingRisk(null);
      }}
    />
    {showProfile && <ProfileModal
      user={user}
      profileName={profileName}
      setProfileName={setProfileName}
      profileEmail={profileEmail}
      setProfileEmail={setProfileEmail}
      onSave={()=>{setShowProfile(false); showToast('Profile updated!', 'success');}}
      onClose={()=>setShowProfile(false)}
    />}
    {toast&&<Toast message={toast.message} type={toast.type} onClose={()=>setToast(null)}/>}
    </>
  );
}

function App() {
  const { isAuthenticated, isLoading } = useAuth0();
  if (isLoading) return <LoadingScreen/>;
  return isAuthenticated ? <Dashboard/> : <LoginPage/>;
}

export default App;
